INSERT INTO developer (id_developer, name, description) VALUES
(1, 'CD Projekt RED', 'This database entry uses a deliberately long English description for testing LONGTEXT storage. It describes a studio profile, production background, design philosophy, platform support, community expectations, update cadence, and long-term support history. The text is intentionally longer than one thousand characters so the dataset clearly satisfies the requirement for at least one column containing a long text value. The studio focuses on reliable production pipelines, readable user interfaces, stable releases, and content that feels believable inside a PC gaming catalogue. Typical projects include campaign progression, achievement tracking, multiplayer systems, save synchronization, performance options, accessibility settings, localization planning, patch notes, balance updates, and community events. Design documents emphasize clear onboarding, fair difficulty curves, responsive input, rewarding exploration, and achievement goals that sound like something a real player could unlock during normal play. The description also mentions store presentation, screenshots, capsule images, release windows, genre tags, player statistics, compatibility data, and post-launch maintenance. Because the value is stored directly inside the SQL file, it can be imported without external dependencies and used to test search, filtering, sorting, and text rendering in an application interface. This final sentence extends the text further while staying realistic and fully in English for the assignment dataset.'),
