INSERT INTO game_genre (id_game_genre, name, description) VALUES
(1, 'Action Adventure', 'Games built around direct control, traversal, combat pressure, and story-driven objectives. This category can contain layered objectives, secondary systems, optional challenges, player-created stories, and progression that changes depending on decisions made during play. This category can contain layered objectives, secondary systems, optional challenges, player-created stories, and progression that changes depending on decisions made during play. This category can contain layered objectives, secondary systems, optional challenges, player-created stories, and progression that changes depending on decisions made during play. This category can contain layered objectives, secondary systems, optional challenges, player-created stories, and progression that changes depending on decisions made during play. This category can contain layered objectives, secondary systems, optional challenges, player-created stories, and progression that changes depending on decisions made during play. This category can contain layered objectives, secondary systems, optional challenges, player-created stories, and progression that changes depending on decisions made during play. This category can contain layered objectives, secondary systems, optional challenges, player-created stories, and progression that changes depending on decisions made during play. This category can contain layered objectives, secondary systems, optional challenges, player-created stories, and progression that changes depending on decisions made during play. This category can contain layered objectives, secondary systems, optional challenges, player-created stories, and progression that changes depending on decisions made during play.'),
(2, 'Open World RPG', 'Role-playing games with broad maps, character progression, side quests, and player-led exploration.'),
(3, 'Tactical Strategy', 'Decision-heavy strategy games where positioning, timing, resources, and planning matter more than reflexes.'),
(4, 'Survival Crafting', 'Games about gathering materials, building tools, managing danger, and turning hostile spaces into safe bases.'),
(5, 'Competitive Shooter', 'Skill-focused shooters with weapon mastery, map knowledge, team coordination, and repeatable online matches.'),
(6, 'Cozy Simulation', 'Relaxed games centered on routines, decorating, collecting, farming, social systems, or peaceful long-term goals.'),
(7, 'Narrative Mystery', 'Story games where investigation, dialogue, clues, and player interpretation drive progression.'),
(8, 'Roguelite Action', 'Run-based games with randomized layouts, repeatable builds, permanent unlocks, and escalating challenge.'),
(9, 'Management Sim', 'Games focused on budgets, production chains, staff, infrastructure, and long-term optimization.'),
(10, 'Precision Platformer', 'Platform games built around clean movement, readable hazards, checkpoints, and mastery through practice.'),
(11, 'Puzzle Exploration', 'Games that reward observation, logic, environmental reading, and unusual solutions rather than direct combat.'),
(12, 'Horror Survival', 'Atmospheric games that use limited resources, threat management, sound design, and vulnerability to build tension.'),
(13, 'Racing Motorsport', 'Driving games centered on tracks, vehicles, handling models, upgrades, and competitive lap improvement.'),
(14, 'Sports Career', 'Sports games built around teams, seasons, athletes, progression, training, and match-day performance.'),
(15, 'Grand Strategy', 'Large-scale strategy games about diplomacy, economics, territory, war, and long historical decision chains.'),
(16, 'City Builder', 'Planning games about roads, zoning, services, population needs, and balancing growth with stability.'),
(17, 'Stealth Immersive', 'Games that reward quiet routes, disguise, gadgets, observation, and creative problem solving.'),
(18, 'Soulslike Combat', 'Combat-heavy adventures with stamina management, deliberate attacks, shortcuts, bosses, and high-risk exploration.'),
(19, 'Metroidvania', 'Interconnected side-scrolling worlds where upgrades unlock new paths and backtracking reveals secrets.'),
(20, 'Deckbuilding Strategy', 'Card-driven games where drafting, synergies, probability, and adaptation shape each run or match.'),
(21, 'Rhythm Arcade', 'Timing-based games that connect music, input accuracy, scoring, and escalating pattern recognition.'),
(22, 'Space Simulation', 'Games about flight, exploration, trading, ship systems, planets, stations, or science-fiction travel.'),
(23, 'Automation Sandbox', 'Systems games where conveyors, machines, logistics, and production loops become the main puzzle.'),
(24, 'Historical Combat', 'Games inspired by historical warfare, tactics, weapons, campaigns, or battlefield roles.'),
(25, 'Party Multiplayer', 'Accessible games designed for groups, quick sessions, readable rules, and memorable social chaos.'),
(26, 'Turn-Based RPG', 'Role-playing games with party building, tactical choices, ability timing, and structured encounters.'),
(27, 'Extraction Action', 'Risk-reward games where players enter dangerous zones, collect supplies, and escape before losing progress.'),
(28, 'Life Sim', 'Games about daily routines, relationships, customization, homes, jobs, and slow personal progression.'),
(29, 'Factory Builder', 'Production games centered on layouts, throughput, resource chains, bottlenecks, and scalable design.'),
(30, 'Card Battler', 'Competitive or solo games where card effects, tempo, counters, and deck identity define play.'),
(31, 'Sandbox Creativity', 'Open-ended games built for building, experimenting, modding, sharing, and emergent player goals.'),
(32, 'JRPG Adventure', 'Party-based adventures with strong characters, dramatic arcs, equipment, exploration, and stylized battles.'),
(33, 'Visual Novel', 'Text-led games driven by choices, branching routes, character relationships, and narrative payoff.'),
(34, 'Arcade Fighter', 'Close-combat games about spacing, reads, combos, counters, and head-to-head mastery.'),
(35, 'MMO Progression', 'Online worlds focused on character growth, cooperative content, economies, guilds, and persistent goals.'),
(36, 'Physics Sandbox', 'Games where objects, momentum, collisions, and systemic interactions create the main challenge.'),
(37, 'Bullet Hell', 'Action games with dense projectile patterns, precise movement, short reactions, and score-focused mastery.'),
(38, 'Base Defense', 'Games about preparing positions, upgrading defenses, managing waves, and surviving escalating attacks.'),
(39, 'Detective Adventure', 'Investigation games centered on suspects, evidence boards, interviews, timelines, and careful deduction.'),
(40, 'Naval Strategy', 'Games involving ships, routes, fleets, trade lanes, sea battles, and maritime logistics.'),
(41, 'Mech Combat', 'Games built around heavy machines, loadouts, armor, heat, weapons, and tactical engagements.'),
(42, 'Creature Collector', 'Games about finding, training, evolving, trading, and battling teams of distinct creatures.'),
(43, 'Post-Apocalyptic RPG', 'Role-playing games set after collapse, with scavenging, factions, moral choices, and survival politics.'),
(44, 'Cyberpunk Action', 'Futuristic games with urban systems, hacking, implants, corporations, and fast combat.'),
(45, 'Mythic Fantasy', 'Fantasy games built around legends, gods, monsters, magic, relics, and heroic progression.'),
(46, 'Underwater Exploration', 'Games about diving, pressure, marine spaces, resource recovery, and strange ocean discoveries.'),
(47, 'Social Deduction', 'Multiplayer games where trust, deception, discussion, roles, and timing create the challenge.'),
(48, 'Educational Systems', 'Games that teach through simulation, experimentation, feedback, and playful problem solving.');
