INSERT INTO achievement (id_achievement, name, game_id, number_of_people, description) VALUES
(1, 'The Witcher: Prologue', 1, 144863, 'Win the veteran challenge in The Witcher with limited resources remaining. This achievement is awarded for a specific in-game accomplishment, not for simple menu interaction or random play time.'),
(2, 'Brave Hidden Route', 1, 144329, 'Discover a flawless run in The Witcher while meeting the bonus condition. This achievement is awarded for a specific in-game accomplishment, not for simple menu interaction or random play time.'),
(3, 'Rare The Clean Finish', 1, 143795, 'Upgrade the forgotten archive in The Witcher using a specialized build. This achievement is awarded for a specific in-game accomplishment, not for simple menu interaction or random play time.'),
(4, 'Steady Collector''s Mark', 1, 143261, 'Survive the last checkpoint in The Witcher without relying on shortcuts. This achievement is awarded for a specific in-game accomplishment, not for simple menu interaction or random play time.'),
(5, 'Iron Veteran Trial', 1, 142727, 'Rescue the veteran challenge in The Witcher after exploring the optional path. This achievement is awarded for a specific in-game accomplishment, not for simple menu interaction or random play time.'),
(6, 'The Witcher: Precision Play', 1, 142193, 'Craft a flawless run in The Witcher while keeping every optional target intact. This achievement is awarded for a specific in-game accomplishment, not for simple menu interaction or random play time.'),
(7, 'Sharp Deep Exploration', 1, 141659, 'Defeat the forgotten archive in The Witcher with a clean final sequence. This achievement is awarded for a specific in-game accomplishment, not for simple menu interaction or random play time.'),
